USE campus_security;

-- Course 1
UPDATE sys_course SET 
content = '一、校园消防安全的重要性\n高校是人员密集场所，宿舍、实验室、图书馆等地火灾风险较高。常见的火灾隐患包括：违规使用大功率电器（如热得快、电磁炉）、私拉乱接电线、在宿舍内吸烟或使用明火、实验室易燃易爆化学品管理不当等。\n\n二、宿舍消防安全“十不准”\n1. 不准私接电源、乱拉电线。\n2. 不准使用违规电器（热得快、电炉、电热毯等）。\n3. 不准在宿舍内吸烟或乱扔烟头。\n4. 不准在宿舍内点蜡烛、焚烧杂物。\n5. 不准擅自挪用或损坏消防器材。\n6. 不准堵塞消防通道或锁闭安全出口。\n7. 不准存放易燃易爆危险品。\n8. 不准离开宿舍时电器不断电。\n9. 不准在床上拉接电源玩手机或电脑。\n10. 不准使用劣质排插或长时间充电。\n\n三、灭火器的正确使用方法（提、拔、握、压）\n1. 提：提起灭火器，上下颠倒几次使干粉松动。\n2. 拔：拔掉保险销。\n3. 握：一手握住喷管，对准火焰根部。\n4. 压：另一手压下压把，左右扫射。\n\n四、火场逃生与自救\n1. 保持镇静，迅速判断火势和逃生路线。\n2. 遇到浓烟时，用湿毛巾捂住口鼻，低姿匍匐前进。\n3. 严禁乘坐电梯，必须通过楼梯或消防通道逃生。\n4. 若被困室内，应用湿衣物堵住门缝，向窗外发出求救信号，切勿盲目跳楼。\n5. 身上着火时，应就地打滚压灭火苗，切勿奔跑。',
quiz = '[
  {"question": "使用干粉灭火器的正确步骤口诀是？", "options": ["摇、拔、喷、压", "提、拔、握、压", "拿、开、对、喷", "提、开、瞄、压"], "answer": 1},
  {"question": "在火灾中遇到浓烟时，正确的逃生姿势是？", "options": ["快速奔跑", "低姿匍匐前进", "站立行走", "跳跃前进"], "answer": 1},
  {"question": "火灾发生时，以下哪种逃生方式是绝对禁止的？", "options": ["走消防楼梯", "乘坐电梯", "用湿毛巾捂住口鼻", "向窗外呼救"], "answer": 1},
  {"question": "宿舍内以下哪种行为是允许的？", "options": ["使用热得快烧水", "私拉电线", "离开宿舍时关闭所有电源", "在床上点蜡烛看书"], "answer": 2},
  {"question": "如果身上衣物着火，首先应该做什么？", "options": ["快速奔跑寻找水源", "用手拍打火苗", "就地打滚压灭火苗", "脱下衣服扔掉"], "answer": 2}
]'
WHERE id = 1;

-- Course 2
UPDATE sys_course SET 
content = '一、校园交通安全现状\n随着校园面积的扩大和师生人数的增加，校园内的非机动车（自行车、电动车）数量急剧上升，交通事故频发。主要原因包括：超速行驶、骑车看手机、双手脱把、逆行、违规载人等。\n\n二、非机动车安全骑行规范\n1. 靠右行驶：在校园道路上骑行必须靠右侧，不得在道路中间或左侧逆行。\n2. 控制车速：校园内人员密集，骑行时车速不宜过快，遇到下坡、转弯、路口时应提前减速。\n3. 注意观察：骑车时严禁佩戴耳机听音乐，严禁边骑车边看手机，保持对周围环境的警觉。\n4. 规范停车：自行车和电动车应停放在指定的停车区域，不得随意停放在教学楼出入口、消防通道或盲道上。\n5. 佩戴头盔：骑行电动车时，必须佩戴符合安全标准的头盔，这是保护生命安全的最后一道防线。\n\n三、行人的交通安全\n1. 走人行道：步行时应尽量走人行道，如果没有人行道则靠路边行走。\n2. 过马路：穿越道路时应走斑马线，注意左右来车，确认安全后再通过。\n3. 远离盲区：在校园内遇到大型车辆（如校车、垃圾车、施工车辆）时，应保持安全距离，避免进入车辆的视觉盲区。\n4. 不在道路上嬉戏：严禁在校园道路上追逐打闹、进行体育活动或长时间停留。\n\n四、校园交通事故的应急处理\n1. 发生事故后，首先确保自身安全，将车辆移至路边（如车辆损坏严重则在后方放置警示标志）。\n2. 如有人受伤，应立即拨打120急救电话和校园保卫处电话。\n3. 保护现场，不随意移动伤者，等待专业救援人员到来。',
quiz = '[
  {"question": "在校园内骑行非机动车，正确的做法是？", "options": ["靠左行驶", "靠右行驶", "在道路中间行驶", "S型穿梭行驶"], "answer": 1},
  {"question": "骑行电动车时，以下哪种装备是必须佩戴的？", "options": ["墨镜", "手套", "安全头盔", "护膝"], "answer": 2},
  {"question": "行人在校园内过马路时，正确的做法是？", "options": ["直接横穿马路", "走斑马线并注意左右来车", "边看手机边过马路", "跑步冲过马路"], "answer": 1},
  {"question": "在校园道路上骑车时，以下哪种行为是绝对禁止的？", "options": ["双手握把", "提前减速转弯", "边骑车边看手机", "按规定停放车辆"], "answer": 2},
  {"question": "遇到校园内的大型车辆时，行人应该怎么做？", "options": ["紧贴车辆行走", "在车辆盲区内停留", "保持安全距离", "与车辆赛跑"], "answer": 2}
]'
WHERE id = 2;

-- Course 3
UPDATE sys_course SET 
content = '一、电信网络诈骗的严峻形势\n近年来，针对大学生的电信网络诈骗案件频发，诈骗手法层出不穷，给学生造成了巨大的经济损失和心理创伤。大学生由于社会经验不足、防范意识薄弱，容易成为诈骗分子的目标。\n\n二、校园常见高发诈骗类型\n1. 刷单返利诈骗：诈骗分子通过QQ、微信、兼职群等渠道发布“动动手指就能赚钱”的刷单广告。前期会返还小额本金和佣金骗取信任，后期要求大额连单，最终以系统故障、操作超时等理由拒绝提现。\n2. 冒充客服退款诈骗：自称淘宝、京东等电商客服，以商品质量问题、快递丢失等理由主动提出多倍退款，诱导受害人离开正规平台，在虚假网站填写银行卡号、密码和验证码。\n3. 冒充公检法诈骗：骗子冒充警察、检察官或法官，称受害人名下银行卡涉嫌洗钱或护照被盗用，利用伪造的通缉令恐吓受害人，要求将资金转入所谓的“安全账户”进行清查。\n4. 杀猪盘与交友诈骗：通过交友软件伪装成“高富帅”或“白富美”，建立恋爱关系后，诱导受害人参与虚假的博彩、理财或投资平台。\n5. 校园贷与注销校园贷诈骗：谎称受害人有校园贷记录，如果不注销会影响个人征信，诱导受害人在各大贷款平台贷款后转账给骗子。\n\n三、防范诈骗的“三不一多”原则\n1. 未知链接不点击：不要随意点击短信、邮件或聊天工具中发来的不明链接，不扫描陌生二维码。\n2. 陌生来电不轻信：对于自称公检法、客服、熟人等要求转账的电话，一律保持怀疑。\n3. 个人信息不透露：绝不向任何人提供身份证号、银行卡号、密码、短信验证码等核心信息。\n4. 转账汇款多核实：凡是涉及到钱财交易，必须通过电话或当面与对方核实身份。\n\n四、遭遇诈骗后的正确应对\n1. 立即停止转账，保存所有聊天记录、转账凭证等证据。\n2. 迅速拨打110或96110报警，并联系辅导员和学校保卫处。\n3. 及时联系银行或支付平台，尝试拦截资金或冻结账户。',
quiz = '[
  {"question": "所有网络兼职刷单的本质是什么？", "options": ["合法的兼职工作", "诈骗", "电商平台的推广手段", "快速致富的捷径"], "answer": 1},
  {"question": "接到自称警察的电话，要求你把钱转到“安全账户”，你应该？", "options": ["立刻转账以证清白", "挂断电话并拨打110核实", "向对方提供银行卡密码", "按对方要求保密不告诉任何人"], "answer": 1},
  {"question": "防范电信网络诈骗的“三不一多”原则中，“多”指的是什么？", "options": ["多赚钱", "多交友", "转账汇款多核实", "多点击链接"], "answer": 2},
  {"question": "如果客服打电话说你购买的商品有质量问题要给你双倍退款，并让你点击他发来的链接，你应该？", "options": ["点开链接填写银行卡信息", "感谢客服并配合操作", "拒绝点击，并通过官方平台联系官方客服核实", "把验证码发给客服"], "answer": 2},
  {"question": "发现自己被骗后，第一时间应该怎么做？", "options": ["自认倒霉，不告诉任何人", "在网上找黑客帮忙追回钱款", "立刻报警并保存好聊天和转账记录", "找骗子理论试图要回钱"], "answer": 2}
]'
WHERE id = 3;

-- Course 4
UPDATE sys_course SET 
content = '一、实验室安全的核心理念\n实验室是高校教学和科研的重要基地。由于实验室中经常使用各种化学药品、易燃易爆物品、剧毒物质以及各类电器设备，如果管理不善或操作不当，极易引发火灾、爆炸、中毒、触电等安全事故。安全是所有实验的前提。\n\n二、实验室基础个人防护\n1. 着装要求：进入实验室必须穿戴长袖实验服（白大褂）、长裤和全封闭的平底鞋。严禁穿拖鞋、凉鞋、短裤、裙子进入。\n2. 护目与手套：进行有危险的化学或生物实验时，必须佩戴护目镜；根据试剂性质选择合适材质的手套（如乳胶、丁腈或防酸碱手套），且手套破损应立即更换。\n3. 长发处理：长发必须扎起，避免卷入仪器设备或沾染化学试剂。\n4. 行为规范：实验室内严禁饮食、吸烟、嚼口香糖，不得存放个人食物或餐具。\n\n三、危险化学品的安全管理\n1. 领用与登记：危险化学品必须严格实行“双人双锁”管理，领用需做好详细的台账记录。\n2. 规范操作：挥发性、有毒有害气体的实验必须在通风橱内进行，操作时通风橱的视窗应降至安全高度（一般为胸部以下）。\n3. 试剂存放：化学试剂应按性质分类存放，强氧化剂与强还原剂、酸与碱必须隔离存放，严禁混放。\n4. 废液处理：严禁将化学废液直接倒入下水道。废液必须分类收集于专用的废液桶中，贴好清晰的成分标签，交由学校专门机构统一处理。\n\n四、仪器设备与用电安全\n1. 资质要求：使用大型、精密或高危险性仪器设备前，必须经过专业培训并取得操作资格。\n2. 规范用电：严禁私自乱拉乱接电线，严禁超负荷用电；离开实验室前必须关闭所有非必须运行的设备电源。\n3. 离人规定：设备运行期间（尤其是加热、加压设备），操作人员严禁擅自离开，必须有人值守。\n\n五、实验室应急处理预案\n1. 熟悉环境：进入实验室第一件事是熟悉消防器材、洗眼器、紧急喷淋装置、逃生通道的位置。\n2. 化学灼伤：强酸强碱等腐蚀性液体溅到皮肤或眼睛上，应立即使用洗眼器或紧急喷淋装置用大量流动清水冲洗至少15分钟，随后立即就医。\n3. 泄漏事故：发生有毒气体或易燃液体大量泄漏时，应立即停止实验，切断火源和电源，打开窗户通风，疏散人员并报警。',
quiz = '[
  {"question": "进入化学实验室进行实验时，以下哪种着装是不允许的？", "options": ["长袖实验服", "长裤", "全封闭平底鞋", "短裤和凉鞋"], "answer": 3},
  {"question": "进行挥发性、有毒气体实验时，必须在哪里进行？", "options": ["实验台面上", "通风橱内", "走廊上", "水池旁"], "answer": 1},
  {"question": "实验产生的化学废液应该如何处理？", "options": ["直接倒入下水道", "倒入垃圾桶", "分类收集于专用废液桶并贴好标签", "带回宿舍"], "answer": 2},
  {"question": "强酸或强碱不慎溅入眼睛，首先应该采取的急救措施是？", "options": ["用手揉眼睛", "用纸巾擦拭", "立即用洗眼器大量清水冲洗至少15分钟", "直接去医院不作处理"], "answer": 2},
  {"question": "关于实验室用电和设备安全，以下说法正确的是？", "options": ["加热设备运行期间可以回宿舍休息", "可以私拉乱接电线", "大型仪器不需要培训即可使用", "离开实验室前应关闭非必须运行的电源"], "answer": 3}
]'
WHERE id = 4;

-- Course 5
UPDATE sys_course SET 
content = '一、正确认识大学生心理健康\n大学阶段是青年学生心理发展、自我认同和人格完善的关键时期。面对适应新环境、学业压力、人际交往、恋爱挫折以及未来的就业选择，大学生很容易产生各种心理困惑和冲突。心理健康不仅仅是没有心理疾病，更是指能够良好地适应环境，保持积极的情绪，拥有和谐的人际关系和健全的人格。\n\n二、大学生常见的心理困惑与危机\n1. 适应障碍：常见于大一新生，表现为失眠、食欲不振、过度怀念家乡和过去、对新环境感到焦虑和排斥。\n2. 学业与就业焦虑：期末考试前、面临考研或找工作时，出现过度紧张、注意力无法集中，甚至引发躯体化症状（如胃痛、头痛、心悸）。\n3. 人际交往与情感挫折：在宿舍关系中感到被孤立，或在恋爱关系破裂（失恋）后产生极度的痛苦、自我否定，甚至出现极端的报复或自残念头。\n4. 抑郁与心理危机：长期情绪低落、对原本感兴趣的事物丧失兴趣、感到持续的疲惫、觉得自己毫无价值，严重时可能出现自杀意念。\n\n三、自我心理调适的科学方法\n1. 建立合理认知：接受自己的不完美，认识到挫折是成长的一部分；不要盲目与他人攀比，设定切实可行的小目标。\n2. 积极的情绪宣泄：感到压抑、愤怒或悲伤时，不要憋在心里。可以通过适度的体育运动、听音乐、写日记、看电影，或者向信任的朋友、家人倾诉来释放情绪。\n3. 保持规律作息：充足的睡眠、均衡的饮食和规律的锻炼是维持心理健康的生理基础。熬夜和生理疲惫会显著放大负面情绪。\n\n四、心理危机干预与专业求助\n1. 打破偏见：寻求心理咨询并不是因为“有精神病”或“脆弱”，而是为了更好地了解自己、解决困惑、获得专业的支持。这是一项勇敢且明智的选择。\n2. 识别危机信号：如果你发现自己或身边的同学出现长时间的极度悲伤、频繁谈论死亡或解脱、将自己珍贵的物品分发给他人、性格突然发生巨大改变等异常行为，必须高度警惕。\n3. 紧急求助途径：当遇到无法跨越的心理障碍时，请立即向辅导员报告，或主动前往学校的心理健康教育中心。学校提供免费、严格保密的心理咨询服务。在紧急情况下，可拨打24小时国家心理援助热线或危机干预热线。',
quiz = '[
  {"question": "寻求心理咨询意味着什么？", "options": ["意味着这个人有严重的精神病", "意味着这个人很脆弱", "是为了更好地了解自己和解决困惑的积极选择", "是一件丢人的事情"], "answer": 2},
  {"question": "当同学遭遇失恋等重大情感挫折，长期情绪低落并谈论轻生时，你应该？", "options": ["觉得他只是说说而已，不用管", "鼓励他去实施", "替他保密，谁也不告诉", "立即向辅导员或心理健康中心报告"], "answer": 3},
  {"question": "以下哪种做法不利于自我心理调适？", "options": ["保持规律作息和充足睡眠", "将所有负面情绪憋在心里不告诉任何人", "通过运动释放压力", "向信任的朋友倾诉"], "answer": 1},
  {"question": "心理健康的标准不仅仅是没有心理疾病，还包括？", "options": ["门门功课考满分", "拥有绝对的财富", "良好地适应环境，保持积极情绪与和谐人际关系", "从不感到悲伤或愤怒"], "answer": 2},
  {"question": "关于大学生常见心理困惑，以下描述错误的是？", "options": ["新生入学容易出现适应障碍", "期末考试前可能出现学业焦虑", "所有人都不可能遇到人际交往障碍", "失恋可能导致严重的自我否定"], "answer": 2}
]'
WHERE id = 5;

-- Course 6
UPDATE sys_course SET 
content = '一、校园防盗安全防范\n随着校园环境的日益开放，针对大学生的盗窃案件时有发生。主要的案发地点集中在学生宿舍、图书馆、食堂和体育场馆。\n1. 宿舍防盗：离开宿舍时，哪怕只是去走廊洗手间或打水，也要随手锁门；笔记本电脑、手机、现金等贵重物品不要随意放在靠近窗户的桌面上，不用时应锁入个人储物柜中；夜间休息时必须反锁宿舍门；警惕推销人员或陌生人进入宿舍，遇到可疑人员应及时盘问或报告宿管。\n2. 公共场所防盗：在图书馆、自习室学习时，若需短暂离开，切勿将手机、电脑等贵重物品留在座位上，应随身携带或交由熟识的同学看管；在食堂就餐或体育馆运动时，不要用书包或衣物占座，更不能将装有贵重物品的包随意丢在场边。\n\n二、线下常见防骗套路\n除了网络诈骗，线下校园诈骗同样需要警惕。\n1. 推销诈骗：开学季常有自称学长学姐的人推销伪劣文具、英语报纸、四六级资料或电话卡，往往质量极差且价格虚高，甚至收取费用后不发货。\n2. 培训班与中介诈骗：以“保过班”、“高薪兼职介绍”为名，要求学生一次性缴纳高额培训费或中介费，随后机构跑路或以各种苛刻条件拒绝提供服务。\n3. 借用手机诈骗：在校园内遇到陌生人以“钱包丢失”、“有急事联系家人”为由借用手机，借到后趁学生不备迅速逃跑，或借机盗取手机内的资金。\n\n三、防盗防骗的核心原则\n1. 克服贪利心理：绝大多数诈骗都是利用了受害人贪图小便宜、企图“不劳而获”的心理。切记天上不会掉馅饼。\n2. 增强防范意识：妥善保管个人财物，做到“物不离视线，人走门必锁”。\n3. 谨慎交友与交易：对待陌生人的求助、推销和借款要求，保持理性和警惕，不要轻易掏钱或转账。\n\n四、被盗被骗后的补救措施\n1. 发现物品被盗或意识到被骗后，第一原则是“快”！立即拨打110报警，并通知学校保卫处。\n2. 保护好案发现场，不要随意翻动被盗物品的原始位置，以便警方提取指纹等证据。\n3. 收集并保存所有与骗子接触的证据，包括转账记录、聊天截图、通话录音、骗子体貌特征等，全数提供给公安机关。',
quiz = '[
  {"question": "在图书馆自习时需要去上洗手间，正确的做法是？", "options": ["把手机和电脑留在座位上占座", "请不认识的陌生人帮忙看管", "将贵重物品随身带走或交由熟识的同学看管", "用书本盖住电脑后离开"], "answer": 2},
  {"question": "离开宿舍去隔壁寝室串门，正确的做法是？", "options": ["不锁门，反正马上就回来", "随手锁门", "把门虚掩着", "把钥匙挂在门上"], "answer": 1},
  {"question": "在校园里遇到陌生人以“急事联系家人”为由借用手机，最安全的做法是？", "options": ["直接把手机交给他", "帮他拨号并自己拿着手机开免提让他通话", "把手机给他并告诉他锁屏密码", "转身就跑"], "answer": 1},
  {"question": "开学初有人到宿舍推销“英语四六级保过资料”，你应该？", "options": ["立刻掏钱购买", "向其他同学借钱购买", "拒绝购买并报告宿管阿姨", "把个人信息留给对方"], "answer": 2},
  {"question": "发现自己物品被盗后，第一时间应该怎么做？", "options": ["自己当侦探去调查", "立刻报警并保护好现场，通知学校保卫处", "自认倒霉，重新买一个", "在宿舍群里大骂小偷"], "answer": 1}
]'
WHERE id = 6;